import java.awt.geom.AffineTransform

// Create an affine transformation: scale by (2.0, 3.0) and translate by (10.0, 20.0)
val transform = new AffineTransform()
transform.translate(10.0, 20.0)
transform.scale(2.0, 3.0)

// Apply the transformation to the spatial data generator builder before generating
val generatedData = sc.generateSpatialData
  .affineTransform(transform)
  .uniform(1000)

// Materialize the RDD to verify the generation and transformation
val count = generatedData.count()
assert(count == 1000, s"Expected exactly 1000 generated features, but got $count")

// Verify that the affine transformation was applied correctly
// The default uniform generator creates geometries in the [0, 1] x [0, 1] space.
// After scaling by (2, 3) and translating by (10, 20), all geometries must fall within [10, 12] x [20, 23].
val firstGeom = generatedData.first().getGeometry
val env = firstGeom.getEnvelopeInternal

assert(env.getMinX >= 10.0 && env.getMaxX <= 12.0, s"Transformed X coordinates out of expected bounds: ${env.getMinX} to ${env.getMaxX}")
assert(env.getMinY >= 20.0 && env.getMaxY <= 23.0, s"Transformed Y coordinates out of expected bounds: ${env.getMinY} to ${env.getMaxY}")

println(s"__CHECK__ affineTransform count=$count, first_env=$env")

