val backEnvelope = Reprojector.reprojectEnvelope(targetEnvelope, 3857, 4326)
assert(Math.abs(backEnvelope.getMinX - sourceEnvelope.getMinX) < 0.001, s"Round-trip minX failed: ${backEnvelope.getMinX}")
assert(Math.abs(backEnvelope.getMaxY - sourceEnvelope.getMaxY) < 0.001, s"Round-trip maxY failed: ${backEnvelope.getMaxY}")

